document.addEventListener('DOMContentLoaded',function(){const year=document.getElementById('year');if(year)year.textContent=new Date().getFullYear();const navToggle=document.getElementById('nav-toggle');const primaryNav=document.getElementById('primary-nav');if(navToggle && primaryNav){navToggle.addEventListener('click',()=>{const expanded=navToggle.getAttribute('aria-expanded')==='true';navToggle.setAttribute('aria-expanded',String(!expanded));primaryNav.classList.toggle('open');});}function adjustHeaderSpacing(){const header=document.querySelector('.site-header');if(!header)return;const h=header.offsetHeight || parseInt(getComputedStyle(header).height,10)|| 72;document.documentElement.style.setProperty('--header-height',h+'px');document.body.style.paddingTop=h+'px';}adjustHeaderSpacing();window.addEventListener('resize',adjustHeaderSpacing);window.addEventListener('load',adjustHeaderSpacing);const revealObserver=new IntersectionObserver((entries,obs)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('active');obs.unobserve(entry.target);}});},{threshold: 0.1});const toReveal=document.querySelectorAll('main section,.hero');toReveal.forEach(el=>{el.classList.add('reveal');revealObserver.observe(el);});const navLinks=document.querySelectorAll('.primary-nav a');navLinks.forEach((link,idx)=>{link.classList.add('reveal');link.style.transitionDelay=`${idx * 0.05}s`;revealObserver.observe(link);});const allBodyEls=document.body.querySelectorAll('*');allBodyEls.forEach(el=>{const tag=el.tagName.toLowerCase();if(tag==='script' || tag==='style' || el.id==='bg-video')return;if(!el.classList.contains('reveal')){el.classList.add('reveal');revealObserver.observe(el);}});});